	PromptSHA       string    `json:"promptSHA,omitempty"`
	StartedAt       time.Time `json:"startedAt"`
	EndedAt         time.Time `json:"endedAt,omitempty"`
	DurationMS      int       `json:"durationMs,omitempty"`
